Tut_Data = {
["1"]={["Title"]="Görev Verenler", ["Text"]="Bir göreve başlamak için, görevi veren kişiyle konuş. Başının üzerinde bir ünlem işareti vardır.|n|nOnunla konuşmak için, yaklaş ve üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["1_A"]={["Title"]="Görev Verenler", ["Text"]="Görev verenlerin başının üzerinde bir ünlem işareti bulunur (|TInterface\\OptionsFrame\\UI-OptionsFrame-NewFeatureIcon:0|t). Yapılacak bir görev almak için üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["1_DWARF"]={["Title"]="Görev Verenler", ["Text"]="Görev verenlerin başının üzerinde bir ünlem işareti bulunur (|TInterface\\OptionsFrame\\UI-OptionsFrame-NewFeatureIcon:0|t). |cffffd200Joren Ironstock|r'tan yapılacak bir görev alabilirsin.|n|n|cffffd200Joren Ironstock|r ile konuşmak için üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["1_GNOME"]={["Title"]="Görev Verenler", ["Text"]="Görev verenlerin başının üzerinde bir ünlem işareti bulunur (|TInterface\\OptionsFrame\\UI-OptionsFrame-NewFeatureIcon:0|t). |cffffd200Nevin Twistwrench|r'ten yapılacak bir görev alabilirsin.|n|n|cffffd200Nevin Twistwrench|r ile konuşmak için üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["1_HUMAN"]={["Title"]="Görev Verenler", ["Text"]="Görev verenlerin başının üzerinde bir ünlem işareti bulunur (|TInterface\\OptionsFrame\\UI-OptionsFrame-NewFeatureIcon:0|t). |cffffd200Marshal McBride|r'tan yapılacak bir görev alabilirsin.|n|n|cffffd200Marshal McBride|r ile konuşmak için üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["1_NIGHTELF"]={["Title"]="Görev Verenler", ["Text"]="Görev verenlerin başının üzerinde bir ünlem işareti bulunur (|TInterface\\OptionsFrame\\UI-OptionsFrame-NewFeatureIcon:0|t). |cffffd200Ilthalaine|r'den yapılacak bir görev alabilirsin.|n|n|cffffd200Ilthalaine|r ile konuşmak için üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["1_ORC"]={["Title"]="Görev Verenler", ["Text"]="Görev verenlerin başının üzerinde bir ünlem işareti bulunur (|TInterface\\OptionsFrame\\UI-OptionsFrame-NewFeatureIcon:0|t). |cffffd200Kaltunk|r'tan yapılacak bir görev alabilirsin.|n|n|cffffd200Kaltunk|r ile konuşmak için üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["1_TAUREN"]={["Title"]="Görev Verenler", ["Text"]="Görev verenlerin başının üzerinde bir ünlem işareti bulunur (|TInterface\\OptionsFrame\\UI-OptionsFrame-NewFeatureIcon:0|t). |cffffd200Chief Hawkwind|r'den yapılacak bir görev alabilirsin.|n|n|cffffd200Chief Hawkwind|r ile konuşmak için üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["1_TROLL"]={["Title"]="Görev Verenler", ["Text"]="Görev verenlerin başının üzerinde bir ünlem işareti bulunur (|TInterface\\OptionsFrame\\UI-OptionsFrame-NewFeatureIcon:0|t). |cffffd200Jin'thala|r'dan yapılacak bir görev alabilirsin.|n|n|cffffd200Jin'thala|r ile konuşmak için üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["2"]={["Title"]="Hareket Etme", ["Text"]="Karakterini hareket ettirmek için A, S, D ve W tuşlarını kullan."},
["3"]={["Title"]="Kamera", ["Text"]="|cffffd200Farenin sağ tuşunu|r basılı tutup fareyi hareket ettirerek karakterini döndürebilirsin.|n|nFarenin sol tuşunu basılı tutup fareyi hareket ettirerek etrafına bakınabilirsin."},
["4"]={["Title"]="Hedef Seçme", ["Text"]="Sana dost olan karakterlerle konuşmak için üzerlerine |cffffd200farenin sağ tuşuyla|r tıkla.|n|nBu işlemi yapabilmek için seçtiğin karaktere yeterince yakın olmalısın."},
["4_DWARF"]={["Title"]="Hedef Seçme", ["Text"]="|cffffd200Rockjaw Invader|r'lar yakınında. Onunla savaşmak için herhangi bir |cffffd200Rockjaw Invader|r üzerine |cffffd200farenin sol tuşuyla|r tıkla."},
["4_GNOME"]={["Title"]="Hedef Seçme", ["Text"]="|cffffd200Crazed Leper Gnome|r'lar yakınında. Onunla savaşmak için herhangi bir |cffffd200Crazed Leper Gnome|r üzerine |cffffd200farenin sol tuşuyla|r tıkla."},
["4_HUMAN"]={["Title"]="Hedef Seçme", ["Text"]="|cffffd200Blackrock Battle Worg|r'lar yakınında. Onunla savaşmak için herhangi bir |cffffd200Blackrock Battle Worg|r üzerine |cffffd200farenin sol tuşuyla|r tıkla."},
["4_NIGHTELF"]={["Title"]="Hedef Seçme", ["Text"]="|cffffd200Young Nightsaber|r'lar yakınında. Onunla savaşmak için herhangi bir |cffffd200Young Nightsaber|r üzerine |cffffd200farenin sol tuşuyla|r tıkla."},
["4_ORC"]={["Title"]="Hedef Seçme", ["Text"]="|cffffd200Mottled Boar|r'lar yakınında. Onunla savaşmak için herhangi bir |cffffd200Mottled Boar|r üzerine |cffffd200farenin sol tuşuyla|r tıkla."},
["4_TAUREN"]={["Title"]="Hedef Seçme", ["Text"]="|cffffd200Bristleback Invader|r'lar yakınında. Onunla savaşmak için herhangi bir |cffffd200Bristleback Invader|r üzerine |cffffd200farenin sol tuşuyla|r tıkla."},
["4_TROLL"]={["Title"]="Hedef Seçme", ["Text"]="|cffffd200Tiki Target|r'lar yakınında. Onunla savaşmak için herhangi bir |cffffd200Tiki Target|r üzerine |cffffd200farenin sol tuşuyla|r tıkla."},
["5"]={["Title"]="Savaş Modu", ["Text"]="Düşmanlarla savaşmak için önce onları seçmek üzere |cffffd200farenin sol tuşunu|r kullan. Ardından ekranın altındaki özel çubukta bulunan yeteneklerinden birine tıkla.|n|nHedefin sana hâlâ uzaktayken menzilli saldırı yeteneklerini kullanmalısın. Diğer yetenekler, özellikle seçtiğin karakter sınıfı yakın dövüş silahlarında uzmanlaşmışsa, hedefe yakın olmanı gerektirir."},
["6"]={["Title"]="Büyüler ve Yetenekler", ["Text"]="Yeteneklerinin çoğu, silah kullanarak yapılan saldırılar veya savaş büyüleridir.|n|nSınıfına bağlı olarak, eylem çubuğunda savunma yeteneklerin, hatta iyileştirme büyülerin bile olabilir."},
["7"]={["Title"]="Ganimet", ["Text"]="Bir düşmanı yenip cesedinin parıldadığını görürsen, bu üzerinde bir ganimet bulacağın anlamına gelir.|n|nCesedi yağmalamak için üzerine |cffffd200farenin sağ tuşuyla|r tıkla. Özel bir pencere açılacak. Bu penceredeki herhangi bir eşyayı çantana taşımak için üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["8"]={["Title"]="Çanta", ["Text"]="Çantana bir eşya girdi.|n|nÇantayı açmak için ekranın sağ alt köşesindeki |cffffd200Çanta Simgesine|r tıklayabilirsin. Ne olduğunu görmek için fare imlecini eşyanın simgesinin üzerine getir."},
["9"]={["Title"]="Eşya Kullanma", ["Text"]="Bazı eşyalar kullanılabilir. Bir eşyayı kullanmak için üzerine |cffffd200farenin sağ tuşuyla|r tıkla.|n|nBir eşyayı çantanı açmadan kullanmak istersen, onu eylem çubuğuna sürükleyebilirsin."},
["10"]={["Title"]="Çantalar", ["Text"]="Bir çanta aldın. Artık daha fazla eşya taşıyabileceksin.|n|nÇantayı, ana çantanın yanındaki boş çanta yuvasına taşı. Açmak için üzerine tıkla."},
["10_DWARF"]={["Title"]="Görev", ["Text"]="|cffffd200Rockjaw Invader|r'ları öldürme görevini aldın.|n|nOnu bulmak için ekranın sağ üst köşesindeki mini haritadan yararlan."},
["10_GNOME"]={["Title"]="Görev", ["Text"]="|cffffd200Crazed Leper Gnome|r'ları öldürme görevini aldın.|n|nOnu bulmak için ekranın sağ üst köşesindeki mini haritadan yararlan."},
["10_HUMAN"]={["Title"]="Görev", ["Text"]="|cffffd200Blackrock Battle Worg|r'ları öldürme görevini aldın.|n|nOnu bulmak için ekranın sağ üst köşesindeki mini haritadan yararlan."},
["10_NIGHTELF"]={["Title"]="Görev", ["Text"]="|cffffd200Young Nightsaber|r'ları öldürme görevini aldın.|n|nOnu bulmak için ekranın sağ üst köşesindeki mini haritadan yararlan."},
["10_ORC"]={["Title"]="Görev", ["Text"]="|cffffd200Mottled Boar|r'ları öldürme görevini aldın.|n|nOnu bulmak için ekranın sağ üst köşesindeki mini haritadan yararlan."},
["10_TAUREN"]={["Title"]="Görev", ["Text"]="|cffffd200Bristleback Invader|r'ları öldürme görevini aldın.|n|nOnu bulmak için ekranın sağ üst köşesindeki mini haritadan yararlan."},
["10_TROLL"]={["Title"]="Görev", ["Text"]="|cffffd200Tiki Target|r'ları öldürme görevini aldın.|n|nOnu bulmak için ekranın sağ üst köşesindeki mini haritadan yararlan."},
["11"]={["Title"]="Yiyecek", ["Text"]="Sağlığını daha hızlı geri kazanmak için bir şeyler yiyebilirsin. Yemek için yiyeceğin üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["11_DWARF"]={["Title"]="Savaş", ["Text"]="Daha fazla |cffffd200Rockjaw Invaders|r yen!"},
["11_GNOME"]={["Title"]="Savaş", ["Text"]="Daha fazla |cffffd200Crazed Leper Gnomes|r yen!"},
["11_HUMAN"]={["Title"]="Savaş", ["Text"]="Daha fazla |cffffd200Blackrock Worgs|r yen!"},
["11_NIGHTELF"]={["Title"]="Savaş", ["Text"]="Daha fazla |cffffd200Young Nightsabers|r yen!"},
["11_ORC"]={["Title"]="Savaş", ["Text"]="Daha fazla |cffffd200Mottled Boar|r yen!"},
["11_TAUREN"]={["Title"]="Savaş", ["Text"]="Daha fazla |cffffd200Bristleback Invaders|r yen!"},
["11_TROLL"]={["Title"]="Savaş", ["Text"]="Daha fazla |cffffd200Tiki Targets|r yen!"},
["12"]={["Title"]="İçecekler", ["Text"]="İçecekler sayesinde manayı daha hızlı geri kazanabilirsin. İçmek için içeceğin üzerine |cffffd200farenin sağ tuşuyla|r tıkla.|n|nKarakter sınıfın mana kullanmıyorsa hiçbir şey içmene gerek yoktur."},
["13"]={["Title"]="Yetenekler (Talent)", ["Text"]="Özel bir arayüz sayesinde yeni bir yetenek (talent) öğrenebilirsin.|n|nEylem çubuğundaki yanıp sönen |cffffd200Yetenek Simgesine|r tıklayarak yetenek sayfasını aç."},
["14"]={["Title"]="Eğitmenler", ["Text"]="Yeni yetenekler öğrenmek için özel bir eğitmene gidebilirsin. Onunla konuşmak için üzerine |cffffd200farenin sağ tuşuyla|r tıkla.|n|nEğitmenler birçok şehir ve kasabada, ayrıca her zaman başlangıç bölgelerinde bulunur. Bazen onları bulmadan önce biraz aramak zorunda kalabilirsin."},
["15"]={["Title"]="Büyü ve Yetenek Kitabı", ["Text"]="Ekranın altındaki |cffffd200Büyü ve Yetenek Kitabı Simgesine|r tıklayıp ardından yetenek simgesini eylem çubuğuna sürükleyerek büyüleri ve yetenekleri eylem çubuğuna taşıyabilirsin.|n|nAyrıca Büyü Kitabı'nın içinde doğrudan üzerlerine tıklayarak bir büyü veya yetenek kullanabilirsin."},
["16"]={["Title"]="İtibar (Reputation)", ["Text"]="İtibar sekmesinden çeşitli hizipler nezdindeki itibarını kontrol edebilirsin.|n|nİtibar sekmesini bulmak için |cffffd200Karakter Bilgisi Simgesine|r tıkla."},
["17"]={["Title"]="Yanıt Verme", ["Text"]="Klavyedeki R tuşuna basıp ardından mesajını yazarak ya da /tell yazıp ardından iletmek istediğin içeriği yazarak başka bir oyuncuya yanıt verebilirsin."},
["18"]={["Title"]="Gruplar", ["Text"]="Başka bir oyuncuyu grubuna davet etmek için portresinin üzerine |cffffd200farenin sağ tuşuyla|r tıklayıp menüden |cffffd200Invite|r seçeneğini seç.|n|nKendi portrenin üzerine farenin sağ tuşuyla tıklayıp gruptan ayrılma seçeneğini seçerek gruptan ayrılabilirsin."},
["19"]={["Title"]="Oyuncular", ["Text"]="Bu, bir karakteri oynayan başka bir oyuncudur. Onu, başının üzerinde mavi renkte bir isim bulunmasından tanıyabilirsin."},
["20"]={["Title"]="Satıcılar", ["Text"]="Yeterince paran olduğu sürece, ticaret penceresindeki bir eşyanın üzerine |cffffd200farenin sağ tuşuyla|r tıklamak o eşyayı satın almanı sağlar.|n|nTicaret penceresi açıkken, üzerine farenin sağ tuşuyla tıklayarak çantandaki herhangi bir eşyayı satabilirsin."},
["21"]={["Title"]="Görev Listesi", ["Text"]="Ekranın alt kısmındaki |cffffd200Görev Günlüğü|r simgesine tıklayarak mevcut görevlerini görüntüleyebilirsin.|n|nEkranın sağ üst köşesindeki |cffffd200Dünya Haritası|r simgesine tıklayarak görevlerin konumlarını görüntüleyebilirsin."},
["22"]={["Title"]="Arkadaşlar", ["Text"]="Burada birlikte oynamaktan hoşlandığın başka bir oyuncu varsa, onu arkadaş listene ekle! |cffffd200Sosyal Düğmesine|r tıkla ve onu arkadaş listene ekle.|n|nYalnızca kendi dünyandan arkadaş ekleyebilirsin."},
["23"]={["Title"]="Sohbet", ["Text"]="Enter tuşuna basıp mesajını yazarak ve ardından tekrar Enter tuşuna basarak bir mesaj gönderebilirsin. Yakınındaki diğer oyuncular söylediklerini duyacaktır."},
["24"]={["Title"]="Giyilebilen Eşyalar", ["Text"]="Önce ekranın alt kısmındaki |cffffd200Karakter Bilgisi|r düğmesine, ardından ekranın sağ alt köşesindeki |cffffd200Çanta|r düğmesine tıklayarak eşya giyebilirsin.|n|nArdından eşyayı çantandan karakterinin uygun ekipman yuvasına sürükle."},
["25"]={["Title"]="Ölüm", ["Text"]="Şimdi bir hayaletsin. Cesedini bularak veya yakınındaki bir şifacıyla konuşarak hayata geri dönebilirsin.|n|nCesedin, ekranın sağ üst kısmındaki mini haritada bir simge olarak görünür."},
["26"]={["Title"]="Dinlenme", ["Text"]="Dinlenmiş durumdasın. Dinlenme, canavarları öldürdükten sonra geçici bir deneyim bonusu verir."},
["27"]={["Title"]="Yorgunluk", ["Text"]="Derin ve bilinmeyen sulara açılırsan, bir yorgunluk (Fatigue) çubuğu göreceksin. Tamamen yorulursan boğulmaya başlarsın."},
["28"]={["Title"]="Yüzme", ["Text"]="Yüzmek yürümek gibidir, ancak |cffffd200farenin sağ tuşunu|r basılı tutup yüzmek istediğin yöne bakarak yukarı ve aşağı yön verebilirsin."},
["29"]={["Title"]="Nefes Alma", ["Text"]="Karakterin suya daldığında bir nefes (Breath) çubuğu göreceksin. Nefesin tükenirse boğulmaya başlarsın."},
["30"]={["Title"]="Dinlenme", ["Text"]="Sarı renkte parlayan portrenin de gösterdiği gibi, şu anda dinleniyorsun. Dinlenerek veya oyun dışında geçirdiğin süre, canavarları öldürdükten sonra sana geçici bir deneyim bonusu verir.|n|nDinlenmek için Hearthstone'unu (Dönüş Taşı) kullanarak hızlıca bir hana dönebilirsin."},
["31"]={["Title"]="Dönüş Taşları", ["Text"]="Dönüş Taşları (Hearthstone), bulunduğun konumdan geçici olarak kayıt yaptırdığın hana ışınlanmak için kullanılabilir."},
["32"]={["Title"]="Oyuncular Arası Savaş", ["Text"]="Diğer oyuncularla savaşa giriyorsun. Düello sırasında, ittifakının sembolü portrenin yanında görünür ve düşman oyuncular tarafından saldırıya uğrayabilirsin."},
["33"]={["Title"]="Zıplama", ["Text"]="Zıplamak için |cffffd200Boşluk tuşuna|r basabilirsin. Engelleri aşmak ya da sadece eğlence için zıplayabilirsin."},
["34"]={["Title"]="Görevi Tamamlama", ["Text"]="İlk görevini tamamladın! Ödülü almak için, görevi belirli bir görev vereniyle tamamlaman gerekir. Bu genellikle sana görevi veren NPC'nin aynısıdır.|n|nYakınındaki görev verenleri, ekranın sağ üst köşesindeki mini haritada |cffffd200?|r olarak görebilirsin. Görev verenle konuşmak için üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["35"]={["Title"]="Seyahat Etme", ["Text"]="Bu bir uçuş ustası; yolcuları bir yerden başka bir yere taşımak için uçan canavarları eğitir. Küçük bir ücret karşılığında, geçmişte konuştuğun diğer uçuş ustalarına hızlıca gidebilirsin.|n|nYeni bir şehir keşfettiğinde, bir uçuş ustası bulmak gelecekte buraya kolayca dönmeni sağlar."},
["36"]={["Title"]="Hasarlı Eşyalar", ["Text"]="Eşyalarından birinin dayanıklılığı giderek azalıyor. Mini haritanın altındaki karakter simgesi, hasarlı eşyayı sarı renkte gösterir.|n|nEşya tamamen bozulmadan önce onarmak için şehirde bir demirci bul."},
["37"]={["Title"]="Bozuk Eşyalar", ["Text"]="Eşyalarından biri bozuldu! Mini haritanın altındaki karakter simgesi, hasarlı eşyayı kırmızı renkte gösterir.|n|nEşyayı şehirdeki bir demircide onarabilirsin. Bunu yapana kadar o eşyayı tam olarak kullanamazsın."},
["38"]={["Title"]="Meslekler", ["Text"]="Karakterin, sana değerli eşyalar bulma veya yaratma imkânı verecek Yemek Pişirme ya da Demircilik gibi meslekler öğrenebilir.|n|nMeslekler hakkında daha fazla bilgi için, büyük bir şehirdeki bir muhafıza meslek eğitmenlerine nasıl ulaşacağını söylemesini iste."},
["39"]={["Title"]="Gruplar", ["Text"]="Düşmanları daha kolay yenebilmek için diğer oyuncuları iş birliğine davet edebilirsin.|n|nBir grupta birçok zor görev hızlıca tamamlanabilir, çünkü tüm katılımcıların eylemleri görevin sonucunu etkiler. Ayrıca gruplar, tek başına oynayan oyunculara kıyasla ekstra deneyim kazanır."},
["40"]={["Title"]="Büyü Kitabı", ["Text"]="Yeni bir büyü veya yetenek öğrendin! Büyü Kitabı'nı açmak için ekranın altındaki |cffffd200Büyü ve Yetenek Kitabı|r simgesini kullan. Bir büyüyü veya yeteneği eylem çubuğuna taşımak için üzerine |cffffd200farenin sol tuşuyla tıklayıp sürükle|r.|n|nBüyü Kitabı, kitabın sağ tarafından çıkan sekmelerin de gösterdiği gibi kategorilere göre düzenlenmiştir."},
["41"]={["Title"]="Elit Görevler", ["Text"]="Bir elit görevi kabul ettin. Bu tür görevler en iyi grup hâlinde yapılır, çünkü seni elit yaratıkların yaşadığı bölgelere götürürler.|n|nElit canavarlar normallerden çok daha güçlüdür; ancak onlardan daha fazla deneyim alırsın. Bir elit yaratığı, portresini çevreleyen altın rengi bir ejderhadan tanıyabilirsin."},
["42"]={["Title"]="World of Warcraft'a Hoş Geldin!", ["Text"]="Oyuna başlamak için, yapılacak bir |cffffd200Görev|r almalısın.|n|nTam karşında bir görev veren var. Öğreticide gösterilen ipuçları oyunun ilerleyen kısımlarında sana yardımcı olacak.|n|nSunucumuzda oynadığın için teşekkür ederiz ve maceralarında başarılar dileriz!"},
["43"]={["Title"]="Erişilemeyen Görev Verenler", ["Text"]="Başının üzerinde gri renkte bir '!' bulunan görev veren, seninkinden daha yüksek seviyede bir göreve sahiptir. Birkaç seviye daha kazandığında ona geri dön."},
["44"]={["Title"]="Menzilli Silahlar", ["Text"]="Bir menzilli silah elde ettin. Kullanmak için, önce |cffffd200Karakter Bilgisi|r ve |cffffd200Çanta|r pencereni açıp seçtiğin eşyayı karakterinin üzerine sürükleyerek bu silahı kuşan.|n|nArdından |cffffd200Büyü Kitabı|r'nı aç ve |cffffd200Atış|r veya |cffffd200Fırlatma|r yeteneğini eylem çubuğuna sürükle.|n|nYalnızca avcılar, savaşçılar ve hırsızlar menzilli silah kullanabilir. Büyücüler, rahipler ve büyü ustaları (warlock) asa (wand) kullanabilir."},
["45"]={["Title"]="Mühimmat", ["Text"]="Yaylar ve tüfekler mühimmat olmadan ateşlenemez. Mühimmat satın almak için şehirdeki bir silah ya da yay satıcısını ziyaret et. Mühimmatı yüklemek için üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["46"]={["Title"]="Akın Grupları (Raid)", ["Text"]="Bir akın grubuna (raid) katıldın: genellikle 10 veya 25 kişilik olsa da, üye sınırı 40'a çıkarılmış bir grup. En zorlu zindanlara girmek veya genellikle yüksek seviyedeki en güçlü düşmanları yenmek için bir akın grubuna ihtiyacın vardır.|n|n|cffff2020Bir akın grubundayken görevlerin çoğundan ilerleme kaydetmezsin. Akın grubundan ayrılmak için karakterinin portresine farenin sağ tuşuyla tıkla ve şu seçeneği seç: gruptan ayrıl.|r"},
["47"]={["Title"]="Totem Çubuğu", ["Text"]="Totem çubuğuna erişim kazandın! Yeni bir element totemine her erişim kazandığında, çubukta yeni bir düğme belirir.|n|nTotem çubuğunda belirli bir element toteminin yalnızca tek bir büyüsü bulunabilir. Daha yüksek seviyelerde birkaç totemi aynı anda yerleştirme yeteneğini kazanırsın."},
["48"]={["Title"]="Savaş Alanı Sırası", ["Text"]="Bir savaş alanı sırasına alındın. Fare imlecini haritadaki ilgili simgenin üzerine getirerek durumunu kontrol edebilirsin."},
["49"]={["Title"]="Savaş Alanına Sefer", ["Text"]="Artık savaşa katılabilirsin. İletişim penceresinde \"Enter Battle\"a tıkla veya haritadaki savaş alanı simgesine farenin sağ tuşuyla tıkla."},
["50"]={["Title"]="Anahtarlık", ["Text"]="Artık bir anahtarlığın var. Düğmesi, eylem çubuğunda çantalarının solunda bulunur."},
["51"]={["Title"]="Zindanlar", ["Text"]="|cffffd200Zindan Bulucu|r (Dungeon Finder) seçeneğini kullanarak bir zindana girebilir veya zindanı seninle birlikte gezmeye istekli bir oyuncu grubu bulabilirsin. Eylem çubuğunun ortasındaki göz düğmesine tıklayarak bundan yararlanabilirsin."},
["52"]={["Title"]="Yoldaşlar", ["Text"]="Tebrikler, az önce ilk yoldaşını edindin. Bu küçük dost, Azeroth'taki ve ötesindeki tüm maceralarında sana eşlik edecek.|n|nTüm yoldaşlarını görmek için |cffffd200Karakter|r simgesine tıkla ve ardından ilgili sekmeyi seç."},
["53"]={["Title"]="Binekler", ["Text"]="Tebrikler, ilk bineğini nasıl çağıracağını öğrendin. Bu güçlü yaratık, Azeroth'taki ve ötesindeki maceralarında seni sırtında taşıyacak.|n|nTüm bineklerini görmek istersen, |cffffd200Karakter|r simgesine tıkla ve ilgili sekmeyi ara. Kolaylık olması için, en sevdiğin bineğin simgesini eylem çubuğuna sürükleyebilirsin."},
["54"]={["Title"]="Tehdit Uyarısı", ["Text"]="Bir düşmanın dikkatini çektin.|n|nKırmızı parıltı, bu yaratığın sana saldırdığı anlamına gelir. Sarı, sana saldırabileceği anlamına gelir. Turuncu, yaratığın sana saldırdığı ancak yakında başka bir hedefe yönelebileceği anlamına gelir."},
["55"]={["Title"]="Bam!", ["Text"]="Tebrikler! Az önce daha yüksek bir seviyeye ulaştın ve daha güçlü hâle geldin.|n|nSınıf eğitmenini ziyaret edip ondan yeni yetenekler öğrenip öğrenemeyeceğine bakabilirsin."},
["55_A"]={["Title"]="Görev Tamamlandı", ["Text"]="Tebrikler! Görevini tamamlamak için yeterli sayıda hedef öldürdün.|n|nÖdülü almak için görev verene geri dön."},
["55_DWARF"]={["Title"]="Görev Tamamlandı", ["Text"]="Tebrikler! Görevini tamamlamak için yeterli sayıda |cffffd200Rockjaw Invader|r öldürdün.|n|nÖdülü almak için |cffffd200Joren Ironstock|r'a geri dön."},
["55_GNOME"]={["Title"]="Görev Tamamlandı", ["Text"]="Tebrikler! Görevini tamamlamak için yeterli sayıda |cffffd200Crazed Leper Gnome|r öldürdün.|n|nÖdülü almak için |cffffd200Nevin Twistwrench|r'e geri dön."},
["55_HUMAN"]={["Title"]="Görev Tamamlandı", ["Text"]="Tebrikler! Görevini tamamlamak için yeterli sayıda |cffffd200Blackrock Battle Worg|r öldürdün.|n|nÖdülü almak için |cffffd200Marshal McBride|r'a geri dön."},
["55_NIGHTELF"]={["Title"]="Görev Tamamlandı", ["Text"]="Tebrikler! Görevini tamamlamak için yeterli sayıda |cffffd200Young Nightsaber|r öldürdün.|n|nÖdülü almak için |cffffd200Ilthalaine|r'e geri dön."},
["55_ORC"]={["Title"]="Görev Tamamlandı", ["Text"]="Tebrikler! Görevini tamamlamak için yeterli sayıda |cffffd200Mottled Boar|r öldürdün.|n|nÖdülü almak için |cffffd200Gornek|r'e geri dön."},
["55_TAUREN"]={["Title"]="Görev Tamamlandı", ["Text"]="Tebrikler! Görevini tamamlamak için yeterli sayıda |cffffd200Bristleback Invader|r öldürdün.|n|nÖdülü almak için |cffffd200Grull Hawkwind|r'e geri dön."},
["55_TROLL_HUNTER"]={["Title"]="Görev Tamamlandı", ["Text"]="Tebrikler! Görevini tamamlamak için yeterli sayıda |cffffd200Tiki Target|r öldürdün.|n|nÖdülü almak için |cffffd200Ortezza|r'ya geri dön."},
["55_TROLL_PRIEST"]={["Title"]="Görev Tamamlandı", ["Text"]="Tebrikler! Görevini tamamlamak için yeterli sayıda |cffffd200Tiki Target|r öldürdün.|n|nÖdülü almak için |cffffd200Tunari|r'ye geri dön."},
["55_TROLL_ROGUE"]={["Title"]="Görev Tamamlandı", ["Text"]="Tebrikler! Görevini tamamlamak için yeterli sayıda |cffffd200Tiki Target|r öldürdün.|n|nÖdülü almak için |cffffd200Legati|r'ye geri dön."},
["56"]={["Title"]="Oyuncu Durumu", ["Text"]="Ekranının sol üst köşesinde yeşil sağlık çubuğun bulunur. Sıfıra ulaştığında ölürsün, bu yüzden dikkatli olmalısın.|n|nSağlık çubuğunun altında, öfke, enerji ya da mana gibi özel yetenekleri kullanmak için gereken gücü gösteren ikinci bir çubuk bulunur. Zamanla iki çubuk da yavaşça dolacaktır."},
["57"]={["Title"]="Düşman Durumu", ["Text"]="Düşmanların da tıpkı senin gibi yeşil sağlık çubukları vardır. Bir düşmanı seçtiğinde, sağlık çubuğunu ekranın üst kısmında görebilir ve onu ne zaman yeneceğini tahmin edebilirsin."},
["57_HUMAN"]={["Title"]="Hatırlatma", ["Text"]="|cffffd200Marshal McBride|r'ı ziyaret etmeyi unutma. Senin için bir görevi var! İmleç |cffffd200Sarı Soru İşaretiyken|r, üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["57_ORC"]={["Title"]="Hatırlatma", ["Text"]="|cffffd200Gornek|r'i ziyaret etmeyi unutma. Senin için bir görevi var! İmleç |cffffd200Sarı Soru İşaretiyken|r, üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["57_TAUREN"]={["Title"]="Hatırlatma", ["Text"]="|cffffd200Grull Hawkwind|r'i ziyaret etmeyi unutma. Senin için bir görevi var! İmleç |cffffd200Sarı Soru İşaretiyken|r, üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["57_TROLL_HUNTER"]={["Title"]="Hatırlatma", ["Text"]="|cffffd200Ortezza|r'yı ziyaret etmeyi unutma. Senin için bir görevi var! İmleç |cffffd200Sarı Soru İşaretiyken|r, üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["57_TROLL_PRIEST"]={["Title"]="Hatırlatma", ["Text"]="|cffffd200Tunari|r'yi ziyaret etmeyi unutma. Senin için bir görevi var! İmleç |cffffd200Sarı Soru İşaretiyken|r, üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["57_TROLL_ROGUE"]={["Title"]="Hatırlatma", ["Text"]="|cffffd200Legati|r'yi ziyaret etmeyi unutma. Senin için bir görevi var! İmleç |cffffd200Sarı Soru İşaretiyken|r, üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["58"]={["Title"]="Dolu Çanta", ["Text"]="Çantalarında yer yok, bu yüzden onlara daha fazla bir şey sığdıramayacaksın. Yer açmak için satıcıları ziyaret et ve gereksiz eşyalarını onlara sat.|n|nSatıcıları çoğunlukla her şehirde, kasabada veya ileri karakolda bulabilirsin."},
["59"]={["Title"]="Çantayı Düzenleme", ["Text"]="Çantanda yer açmak ya da biraz para kazanmak için, şimdiye kadar topladığın bazı eşyaları satabilirsin.|n|nBir satıcı bul ve üzerine |cffffd200farenin sağ tuşuyla|r tıkla. Ardından çantalarını aç ve satmak istediğin eşyaların üzerine |cffffd200farenin sağ tuşuyla|r tıkla."},
["60"]={["Title"]="Özel Yetenekler", ["Text"]="Unutma, karakterinin ekranının alt kısmındaki eylem çubuğunda özel yetenekleri vardır.|n|nBu yetenekleri kullanmak, düşmanı sadece silah sallamaktan çok daha hızlı öldürecektir."},
["61"]={["Title"]="Deneme Sürümü", ["Text"]="Bu, World of Warcraft'ın deneme sürümüdür. Bazı özellikler kullanılamaz. Oyunun tamamını keşfetmek için www.worldofwarcraft.com adresini ziyaret et."},
};
